import React, { useEffect, useState } from 'react';
import { useHistory } from 'react-router-dom';

const CLIENT_ID = 'your-client-id';
const REDIRECT_URI = 'http://localhost:3000/callback';
const AUTHORIZATION_ENDPOINT = 'https://authorization-server.com/auth';
const TOKEN_ENDPOINT = 'https://authorization-server.com/token';

const generateCodeVerifier = () => {
  const array = new Uint32Array(56 / 2);
  window.crypto.getRandomValues(array);
  return Array.from(array, dec => ('0' + dec.toString(16)).substr(-2)).join('');
};

const generateCodeChallenge = async (verifier) => {
  const encoder = new TextEncoder();
  const data = encoder.encode(verifier);
  const digest = await window.crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
};

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const history = useHistory();

  useEffect(() => {
    const code = new URLSearchParams(window.location.search).get('code');
    if (code) {
      const codeVerifier = localStorage.getItem('code_verifier');
      fetchToken(code, codeVerifier);
    }
  }, []);

  const fetchToken = async (code, codeVerifier) => {
    const response = await fetch(TOKEN_ENDPOINT, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        client_id: CLIENT_ID,
        redirect_uri: REDIRECT_URI,
        code_verifier: codeVerifier,
        code: code
      })
    });
    const data = await response.json();
    localStorage.setItem('access_token', data.access_token);
    setIsAuthenticated(true);
    history.push('/');
  };

  const handleLogin = async () => {
    const codeVerifier = generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(codeVerifier);
    localStorage.setItem('code_verifier', codeVerifier);
    const authUrl = `${AUTHORIZATION_ENDPOINT}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&code_challenge=${codeChallenge}&code_challenge_method=S256`;
    window.location.href = authUrl;
  };

  return (
    <div>
      {!isAuthenticated ? (
        <button onClick={handleLogin}>Login with OAuth</button>
      ) : (
        <div>Authenticated</div>
      )}
    </div>
  );
};

export default App;